mapper.select:
SELECT tcu.id, tcl.full_name, tcl.phone, tu.name AS owner_name, tp.name AS product_name, tcu.next_contact_time, tcu.create_time FROM t_customer tcu LEFT JOIN t_clue tcl ON tcu.clue_id = tcl.id LEFT JOIN t_user tu ON tcl.owner_id = tu.id LEFT JOIN t_product tp ON tcu.product = tp.id
AND tcl.full_name LIKE CONCAT('%', #{query.fullName}, '%')
AND tcl.phone LIKE CONCAT('%', #{query.phone}, '%')
AND tcl.owner_id = #{query.ownerId}
AND tcu.product = #{query.productId}
ORDER BY tcu.create_time DESC

SELECT tcl.full_name, tcl.phone, tu.name AS owner_name, tp.name AS product_name, tcu.next_contact_time, tcu.create_time FROM t_customer tcu LEFT JOIN t_clue tcl ON tcu.clue_id = tcl.id LEFT JOIN t_user tu ON tcl.owner_id = tu.id LEFT JOIN t_product tp ON tcu.product = tp.id
AND tcl.full_name LIKE CONCAT('%', #{query.fullName}, '%')
AND tcl.phone LIKE CONCAT('%', #{query.phone}, '%')
AND tcl.owner_id = #{query.ownerId}
AND tcu.product = #{query.productId}
ORDER BY tcu.create_time DESC

SELECT tcl.full_name, tcl.phone, tu.name AS owner_name, tp.name AS product_name, tcu.next_contact_time, tcu.create_time FROM t_customer tcu LEFT JOIN t_clue tcl ON tcu.clue_id = tcl.id LEFT JOIN t_user tu ON tcl.owner_id = tu.id LEFT JOIN t_product tp ON tcu.product = tp.id WHERE tcu.id IN
#{id}
ORDER BY tcu.create_time DESC
